// src/Tools.jsx
import React, { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function Tools({ employee }) {
  const [travelExpenses, setTravelExpenses] = useState([]);
  const [ticketExpenses, setTicketExpenses] = useState([]);
  const [files, setFiles] = useState([]);
  const [message, setMessage] = useState("");
  const navigate = useNavigate();

  useEffect(() => {
    if (employee?.empld) {
      fetchData();
    }
  }, [employee]);

  const fetchData = async () => {
    try {
      const [tRes, kRes] = await Promise.all([
        fetch(
          `${apiBase}/travel-expenses?empld=${encodeURIComponent(
            employee.empld
          )}`
        ),
        fetch(
          `${apiBase}/ticket-expenses?empld=${encodeURIComponent(
            employee.empld
          )}`
        ),
      ]);
      const [travel, tickets] = await Promise.all([
        tRes.json(),
        kRes.json(),
      ]);

      setTravelExpenses(Array.isArray(travel) ? travel : []);
      setTicketExpenses(Array.isArray(tickets) ? tickets : []);
    } catch (err) {
      console.error("Tools fetch error:", err);
    }
  };

  // ───────────────── PIE CHART DATA (Travel vs Ticket) ────────────────
  const { totalTravel, totalTicket, travelAngle } = useMemo(() => {
    const sumTravel = Array.isArray(travelExpenses)
      ? travelExpenses.reduce(
          (sum, t) => sum + Number(t.amount || 0),
          0
        )
      : 0;

    const sumTicket = Array.isArray(ticketExpenses)
      ? ticketExpenses.reduce(
          (sum, t) => sum + Number(t.amount || 0),
          0
        )
      : 0;

    const total = sumTravel + sumTicket;
    const angle = total ? (sumTravel / total) * 360 : 0;

    return {
      totalTravel: sumTravel,
      totalTicket: sumTicket,
      travelAngle: angle,
    };
  }, [travelExpenses, ticketExpenses]);

  // ───────────────── Bill upload (REAL upload) ────────────────
  const handleFileChange = (e) => {
    setFiles(Array.from(e.target.files || []));
  };

  const handleUpload = async (e) => {
    e.preventDefault();
    setMessage("");

    if (!files.length) {
      setMessage("Please select at least one file to upload.");
      return;
    }

    try {
      const formData = new FormData();
      files.forEach((f) => formData.append("bills", f));
      formData.append("empld", employee.empld);

      const res = await fetch(`${apiBase}/upload-bills`, {
        method: "POST",
        body: formData,
      });

      const data = await res.json();

      if (data.success) {
        setMessage("✅ Bills uploaded successfully.");
        setFiles([]);
        // History page will pick these via /bills?empld=...
      } else {
        setMessage("❌ " + (data.message || "Failed to upload bills."));
      }
    } catch (err) {
      console.error("Upload error:", err);
      setMessage("❌ Server error while uploading bills.");
    }
  };

  // ───────────────── Report CSV download ────────────────
  const downloadReport = () => {
    const rows = [
      ["Type", "Date", "Purpose", "AssignedTo/FromTo", "Amount"],
      ...(Array.isArray(travelExpenses)
        ? travelExpenses.map((t) => [
            "Travel",
            t.travel_date,
            t.purpose,
            `${t.location_from || ""} -> ${t.location_to || ""}`,
            t.amount,
          ])
        : []),
      ...(Array.isArray(ticketExpenses)
        ? ticketExpenses.map((t) => [
            "Ticket",
            t.ticket_date,
            t.purpose,
            t.assigned_to || "",
            t.amount,
          ])
        : []),
    ];

    const csvContent = rows
      .map((row) =>
        row.map((cell) => `"${String(cell ?? "").replace(/"/g, '""')}"`).join(",")
      )
      .join("\n");

    const blob = new Blob([csvContent], {
      type: "text/csv;charset=utf-8;",
    });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `prasa-expense-report-${employee.empld}.csv`;
    link.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        padding: 16,
        fontFamily: "Segoe UI",
      }}
    >
      <div
        style={{
          maxWidth: 1000,
          margin: "0 auto",
          background: "#ffffff",
          borderRadius: 16,
          padding: 18,
          boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
        }}
      >
        {/* Back arrow + title */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 10,
            marginBottom: 8,
          }}
        >
          <button
            onClick={() => navigate("/profile")}
            style={{
              background: "transparent",
              border: "none",
              color: green,
              fontSize: 16,
              cursor: "pointer",
            }}
          >
            ⬅ Back
          </button>
          <h2 style={{ color: green, margin: 0 }}>Tools</h2>
        </div>

        <p style={{ fontSize: 13, color: "#555", marginBottom: 16 }}>
          Employee: {employee.name} • {employee.empld}
        </p>

        {/* 1. PIE CHART (Travel vs Ticket) */}
        <section style={{ marginBottom: 24 }}>
          <h3 style={{ color: green, marginBottom: 8 }}>Expense Pie Chart</h3>
          {totalTravel + totalTicket === 0 ? (
            <p style={{ fontSize: 13 }}>No expense data to show yet.</p>
          ) : (
            <div
              style={{
                display: "flex",
                flexWrap: "wrap",
                gap: 20,
                alignItems: "center",
              }}
            >
              {/* Pie */}
              <div
                style={{
                  width: 180,
                  height: 180,
                  borderRadius: "50%",
                  background:
                    totalTravel + totalTicket === 0
                      ? "#ddd"
                      : `conic-gradient(
                          ${green} 0deg ${travelAngle}deg,
                          #8bc34a ${travelAngle}deg 360deg
                        )`,
                  boxShadow: "0 4px 14px rgba(0,0,0,0.15)",
                }}
              />
              {/* Legend */}
              <div style={{ fontSize: 14 }}>
                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    marginBottom: 6,
                  }}
                >
                  <span
                    style={{
                      width: 14,
                      height: 14,
                      background: green,
                      borderRadius: 4,
                      marginRight: 8,
                    }}
                  />
                  Travel Total: ₹{totalTravel.toFixed(2)}
                </div>
                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    marginBottom: 6,
                  }}
                >
                  <span
                    style={{
                      width: 14,
                      height: 14,
                      background: "#8bc34a",
                      borderRadius: 4,
                      marginRight: 8,
                    }}
                  />
                  Ticket Total: ₹{totalTicket.toFixed(2)}
                </div>
              </div>
            </div>
          )}
        </section>

        {/* 2. Bill Upload */}
        <section style={{ marginBottom: 24 }}>
          <h3 style={{ color: green, marginBottom: 8 }}>Bill Upload</h3>
          <p style={{ fontSize: 12, color: "#555", marginBottom: 6 }}>
            Upload your bill PDFs / images. Files are stored inside the backend
            <b> uploads</b> folder, grouped by your Employee ID.
          </p>
          <form
            onSubmit={handleUpload}
            style={{
              background: "#fbfff9",
              padding: 12,
              borderRadius: 12,
              border: `1px solid ${lightGreen}`,
            }}
            encType="multipart/form-data"
          >
            <input
              type="file"
              multiple
              onChange={handleFileChange}
              style={{ marginBottom: 10 }}
            />
            <button
              type="submit"
              style={{
                padding: 8,
                borderRadius: 10,
                border: "none",
                background: green,
                color: "#ffffff",
                fontWeight: 600,
                cursor: "pointer",
              }}
            >
              Upload Bills
            </button>
            {files.length > 0 && (
              <div style={{ marginTop: 8, fontSize: 12 }}>
                Selected: {files.map((f) => f.name).join(", ")}
              </div>
            )}
          </form>
        </section>

        {/* 3. Report Download */}
        <section>
          <h3 style={{ color: green, marginBottom: 8 }}>Report Download</h3>
          <p style={{ fontSize: 13, color: "#555" }}>
            Download a CSV summary of your travel and ticket expenses for your
            own offline report.
          </p>
          <button
            onClick={downloadReport}
            style={{
              padding: 10,
              borderRadius: 10,
              border: "none",
              background: green,
              color: "#ffffff",
              fontWeight: 600,
              cursor: "pointer",
            }}
          >
            Download Report (CSV)
          </button>
        </section>

        {message && (
          <div style={{ marginTop: 10, color: green, fontSize: 13 }}>
            {message}
          </div>
        )}
      </div>
    </div>
  );
}
